  ('cpa-moex-01411', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依營業稅法規定，進口菸品於計算其營業稅應納稅額時，其計稅價格為何？', '["不應包括菸品之菸酒稅額或菸品健康福利捐", "應包括菸品之菸酒稅額，但不包括菸品健康福利捐", "應同時包括菸品之菸酒稅額或菸品健康福利捐", "應包括菸品健康福利捐，但不包括菸品之菸酒稅額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01412', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '某公司外銷貨物未向海關申報出口，而委託國際快遞業者交寄，依營業稅法規定，下列何者不正確？', '["以國際快遞業者出據之執據，作為申報適用零稅率之證明文件", "以國際快遞業者出據之執據所載日期作為申報時點", "以國際快遞業者出據之執據所載貨物價值金額為銷售額", "以國際快遞業者出據之執據所載完稅價格核算稅額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01413', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '稅捐稽徵法對納稅義務人之財產、所得、營業及納稅等課稅資料，有關「保密」之規定，下列敘述何者 正確？', '["對所有人員及機關，應絕對保守秘密，違者應予處分", "稅捐稽徵機關對其他政府機關為統計目的，可提供資料並洩漏納稅義務人之姓名或名稱", "經財政部核定獲得租稅資訊之政府機關或人員不可就其所獲取之租稅資訊，另作其他目的使用", "財政部對重大欠稅案件或重大逃漏稅捐案件經確定後，仍不得公告欠稅人之姓名與內容"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01414', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '經復查、訴願或行政訴訟程序終結決定或判決，應補繳稅款者，稅捐稽徵機關應於復查決定，或接到訴 願決定書，或行政法院判決書正本後十日內，填發補繳稅款繳納通知書，通知納稅義務人繳納；並應按 補繳稅額，依那一年度一月一日郵政儲金一年期定期儲金固定利率，按日加計利息，一併徵收？', '["各年度", "原應繳納年度", "判決確定年度", "原復查、訴願或行政訴訟申請年度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01415', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法有關租稅之優先受償規定，下列敘述何者錯誤？', '["稅捐之徵收，優先於普通債權", "土地增值稅、地價稅、房屋稅之徵收，及法院或行政執行處拍賣、變賣貨物應課徵之營業稅，優先於 一切債權及抵押權", "破產財團成立後，其應納稅捐為財團債務，由破產管理人依公司法之規定清償之", "公司重整中所發生之稅捐，為公司重整債務，依公司法之規定清償之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01416', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，下列敘述何者錯誤？', '["本法所稱稅捐，指一切法定之國、省（市）及縣（市）稅捐；但不包括關稅及礦稅", "財政部得本互惠原則，與外國政府商訂互免稅捐，於報經行政院核准後，以外交換文方式行之", "破產財團成立後，其應納稅捐為財團費用，由破產管理人依破產法之規定清償之", "依稅法規定應自他人取得之憑證及給予他人憑證之存根或副本，應保存10年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01417', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法第31條規定，稅捐稽徵機關對逃漏下列何種稅目，涉有犯罪嫌疑之案件，得聲請當地司法 機關進行搜索？', '["所得稅及遺產稅", "營業稅及遺產稅", "所得稅及營業稅", "土地稅及房屋稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01418', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '下列何種贈與，依遺產及贈與稅法規定其財產「不計入贈與總額」內？', '["祖父贈與孫媳婦之農業用地", "父母贈與已婚子女之財產", "兄於弟結婚時贈與之現金", "夫贈與妻之財產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01419', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，遺產稅及贈與稅納稅義務人，應於稽徵機關送達核定納稅通知書之日起多少時 間內，繳清應納稅款？必要時，得於限期內申請稽徵機關核准延期多少時間？', '["30日；30日", "一個月；二個月", "二個月；二個月", "二個月；三年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01420', 'cpa', 'cpa-moex-103-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '王強僅有美國籍在臺灣無住所，每年在臺灣地區賺到高額所得，最近為贈與子女資金，直接從王強德國 的帳戶匯了相當於新臺幣2,000萬元的美金進入子女在臺灣的帳戶。有關王強的匯款，依遺產及贈與稅相 關規定，下列敘述那一項正確？', '["王強的子女應該在臺灣申報綜合所得稅", "王強的子女應該申報海外所得2,000萬元，並計算所得基本稅額", "應扣除贈與年度之贈與稅免稅額後，課贈與稅", "不課贈與稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "115e12ae00a6", "answer_pdf_sha1": "e69b2366aee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
